import pytest

def test_expired_token_returns_410(
    <api_client_fixture>, <expired_reset_token_fixture>, <totp_fixture>
):
    expired_token = <expired_reset_token_fixture>
    payload = {
        "token": expired_token,
        "new_password": "NewP@ssw0rd!2024",
        "totp_code": <totp_fixture>.now()
    }

    resp = <api_client_fixture>.post("/password/reset", json=payload)

    assert resp.status_code == 410, f"Expected 410, got {resp.status_code}"
    body = resp.json()
    assert body.get("error") == "TOKEN_EXPIRED", f"Unexpected error body: {body}"

    login_resp = <api_client_fixture>.post(
        "/api/login",
        json={"password": "NewP@ssw0rd!2024"}
    )
    assert login_resp.status_code == 401, "Password must remain unchanged after expired token"

import pytest

@pytest.mark.parametrize("bad_password,violation_hint", [
    ("abc", "too_short"),
    ("alllowercase1!", "no_uppercase"),
    ("ALLUPPERCASE1!", "no_lowercase"),
    ("NoSpecialChar1", "no_special"),
])
def test_password_failing_policy_returns_422(
    <api_client_fixture>, <valid_reset_token_fixture>, <totp_fixture>,
    bad_password, violation_hint
):
    payload = {
        "token": <valid_reset_token_fixture>,
        "new_password": bad_password,
        "totp_code": <totp_fixture>.now()
    }

    resp = <api_client_fixture>.post("/password/reset", json=payload)

    assert resp.status_code == 422, (
        f"[{violation_hint}] Expected 422, got {resp.status_code}"
    )
    body = resp.json()
    assert "errors" in body, "Response must contain policy error details"
    assert len(body["errors"]) > 0, "At least one policy violation must be reported"

import pytest
from datetime import datetime, timedelta, timezone

def test_token_at_29min_59sec_is_accepted(
    <api_client_fixture>, <totp_fixture>, <token_factory_fixture>, <session_cookie_fixture>
):
    issued_at = datetime.now(timezone.utc) - timedelta(seconds=1799)  # 29m 59s ago
    near_boundary_token = <token_factory_fixture>.create(issued_at=issued_at)

    old_session = <session_cookie_fixture>
    payload = {
        "token": near_boundary_token,
        "new_password": "V@lidBoundary!Pass1",
        "totp_code": <totp_fixture>.now()
    }

    resp = <api_client_fixture>.post("/password/reset", json=payload)

    assert resp.status_code in (200, 302), (
        f"Token at 29m59s must succeed, got {resp.status_code}"
    )

    session_resp = <api_client_fixture>.get(
        "/api/session", cookies={"session": old_session}
    )
    assert session_resp.status_code == 401, "Old session must be invalidated after reset"

import pytest

def test_invalid_totp_code_blocks_reset(
    <api_client_fixture>, <valid_reset_token_fixture>
):
    payload = {
        "token": <valid_reset_token_fixture>,
        "new_password": "Val!dP@ssw0rd2024",
        "totp_code": "000000"  # deliberately wrong TOTP
    }

    resp = <api_client_fixture>.post("/password/reset", json=payload)

    assert resp.status_code in (401, 403), (
        f"Invalid TOTP must block reset, got {resp.status_code}"
    )
    body = resp.json()
    error_text = str(body).lower()
    assert any(kw in error_text for kw in ("2fa", "otp", "totp", "mfa", "authentication")), (
        f"Response must cite 2FA failure, got: {body}"
    )

    login_resp = <api_client_fixture>.post(
        "/api/login",
        json={"password": "Val!dP@ssw0rd2024"}
    )
    assert login_resp.status_code == 401, "Password must be unchanged after failed 2FA"
